document.addEventListener("DOMContentLoaded",function(){var e=document.querySelector(".hero__video"),t=document.querySelector(".hero__play-btn");e&&t&&t.addEventListener("click",function(){e.paused?(e.play(),t.classList.remove("is-paused")):(e.pause(),t.classList.add("is-paused"))})}),document.addEventListener("DOMContentLoaded",function(){var e=document.querySelectorAll(".js-animate"),t=new IntersectionObserver(function(e,t){e.forEach(function(e){e.isIntersecting&&(e.target.classList.add("is-visible"),t.unobserve(e.target))})},{root:null,rootMargin:"0px",threshold:.15});e.forEach(function(e){t.observe(e)})});